-- Check if player has a technology researched
function LexHelpers.has_technology(tech_id)
    return game_state.technologies and game_state.technologies[tech_id] == true
end

-- Check if player has a structure built
function LexHelpers.has_structure(structure_id)
    return game_state.structures and game_state.structures[structure_id] == true
end

-- Check if player has enough resources
function LexHelpers.has_resources(resource_map)
    for resource, amount in pairs(resource_map) do
        if not (game_state.resources and (game_state.resources[resource] or 0) >= amount) then
            return false
        end
    end
    return true
end

